#define THREADS_PER_BLOCK 256

typedef struct {
  float weight;
  long assign;  
  float cost;  
} Point_Struct;

__attribute__((always_inline))
float dist_kernel(const float* coord1, const float* coord2, int dim) {
  float result = 0.0f;
  for (int i = 0; i < dim; i++) {
    float diff = coord1[i] - coord2[i];
    result += diff * diff;
  }
  return result;
}

__attribute__((always_inline))
float get_coord(const float* all_coords, int point_idx, int coord_idx, int num_points, int dim) {
  return all_coords[point_idx * dim + coord_idx];
}

kernel void pgain_kernel(
    const Point_Struct* p,
    const float* coord_data,
    float* work_mem,
    const int* center_table,
    char* switch_membership,
    int num_points,
    int dim,
    long x_idx,
    int K) {

  int i = get_global_id(0);
  if (i >= num_points) return;

  float x_cost = 0.0f;
  for (int d = 0; d < dim; d++) {
    float p_coord = coord_data[i * dim + d];
    float x_coord = coord_data[x_idx * dim + d];
    float diff = p_coord - x_coord;
    x_cost += diff * diff;
  }
  x_cost *= p[i].weight;

  float current_cost = p[i].cost;

  if (x_cost < current_cost) {
    switch_membership[i] = 1;
    work_mem[i * (K + 1) + K] += x_cost - current_cost;
  } else {
    int assign = (int)p[i].assign;
    int ct_val = center_table[assign];
    if (ct_val >= 0 && ct_val < K) {
      work_mem[i * (K + 1) + ct_val] += current_cost - x_cost;
    }
  }
}
